export const AI_TOOLS_BY_NAME = new Map<string, GeneratedAITool>(
  AI_TOOLS.map((tool) => [tool.metadata.name, tool])
);

export const AI_TOOLS_BY_SCOPE = new Map<string, GeneratedAITool[]>();
for (const tool of AI_TOOLS) {
  for (const scope of tool.metadata.scopes) {
    const existing = AI_TOOLS_BY_SCOPE.get(scope) || [];
    existing.push(tool);
    AI_TOOLS_BY_SCOPE.set(scope, existing);
  }
}

/**
 * Get tools filtered by scope(s)
 */
export function getToolsByScope(scopes: string[]): GeneratedAITool[] {
  const result = new Set<GeneratedAITool>();
  for (const scope of scopes) {
    const tools = AI_TOOLS_BY_SCOPE.get(scope) || [];
    for (const tool of tools) {
      result.add(tool);
    }
  }
  return Array.from(result);
}

/**
 * Get tool by name
 */
export function getToolByName(name: string): GeneratedAITool | undefined {
  return AI_TOOLS_BY_NAME.get(name);
}

/**
 * Get OpenAI-compatible tool definitions for a set of scopes
 */
export function getOpenAITools(scopes: string[]): ChatCompletionTool[] {
  return getToolsByScope(scopes).map((t) => t.functionDeclaration);
}

